const records = {
 R1:{resonance_error_pm:25.9, heater_mW:70.9, q_factor_k:27.8, crosstalk_dB:-15.3},
 R2:{resonance_error_pm:3.4, heater_mW:70.9, q_factor_k:92.4, crosstalk_dB:-24.8},
 R3:{resonance_error_pm:39.8, heater_mW:70.4, q_factor_k:62.9, crosstalk_dB:-30.9},
 R4:{resonance_error_pm:20.8, heater_mW:36.2, q_factor_k:114.5, crosstalk_dB:-34.1},
};
const max = {
 resonance_error_pm: Math.max(...Object.values(records).map(r=>r.resonance_error_pm)),
 heater_mW: Math.max(...Object.values(records).map(r=>r.heater_mW)),
 q_factor_k: Math.max(...Object.values(records).map(r=>r.q_factor_k)),
 crosstalk_abs: Math.max(...Object.values(records).map(r=>Math.abs(r.crosstalk_dB))),
};
console.log(JSON.stringify(max,null,2));
for (const [id,r] of Object.entries(records)) {
  const norm = {
    resonance_error_pm: r.resonance_error_pm/max.resonance_error_pm,
    heater_mW: r.heater_mW/max.heater_mW,
    q_risk: (max.q_factor_k/r.q_factor_k)/(max.q_factor_k/Math.min(...Object.values(records).map(r=>r.q_factor_k))),
    crosstalk_risk: Math.abs(r.crosstalk_dB)/max.crosstalk_abs,
  };
  const score = 0.4*norm.resonance_error_pm+0.3*norm.heater_mW+0.2*norm.q_risk+0.1*norm.crosstalk_risk;
  console.log(id, norm, score);
}
